peaker_name":null},{"text":"I don''t have it in the site map at the moment, but we had talked about spotlighting an upcoming event as a block.","index":201,"end_time":736.04,"speaker_id":1,"start_time":727.56,"speaker_name":null},{"text":"Yeah, that would be useful to be able to like add or subtract at will.","index":202,"end_time":744.41,"speaker_id":0,"start_time":738.36,"speaker_name":null},{"text":"Maybe it would go like between.","index":203,"end_time":750.09,"speaker_id":0,"start_time":748.25,"speaker_name":null},{"text":"I''m trying to decide.","index":204,"end_time":753.85,"speaker_id":0,"start_time":752.65,"speaker_name":null},{"text":"Or we could do kind of what we have right now, which is sometimes it''s up here.","index":205,"end_time":760.33,"speaker_id":0,"start_time":754.01,"speaker_name":null},{"text":"Of course, now there isn''t one, but it''s like above the navigation.","index":206,"end_time":765.31,"speaker_id":0,"start_time":761.05,"speaker_name":null},{"text":"But I will let me talk to our events person and see kind of what she''s thinking.","index":207,"end_time":773.62,"speaker_id":0,"start_time":765.94,"speaker_name":null},{"text":"Okay, that works because we can fit it in both ways.","index":208,"end_time":776.34,"speaker_id":1,"start_time":773.94,"speaker_name":null},{"text":"We could have a separate block and you know, that could always just show the most recent or the.","index":209,"end_time":785.7,"speaker_id":1,"start_time":776.34,"speaker_name":null},{"text":"What''s the best way to describe it?","index":210,"end_time":787.58,"speaker_id":1,"start_time":786.26,"speaker_name":null},{"text":"The one that''s next up on the calendar and that could be automated based on event date.","index":211,"end_time":792.77,"speaker_id":1,"start_time":787.58,"speaker_name":null},{"text":"So where it wouldn''t be something you would have to manually adjust.","index":212,"end_time":797.81,"speaker_id":1,"start_time":793.09,"speaker_name":null},{"text":"Okay.","index":213,"end_time":799.57,"speaker_id":0,"start_time":798.93,"speaker_name":null},{"text":"So something to think about there.","index":214,"end_time":801.81,"speaker_id":1,"start_time":800.21,"speaker_name":null},{"text":"And that would just be like a component.","index":215,"end_time":803.81,"speaker_id":1,"start_time":801.81,"speaker_name":null},{"text":"And we can.","index":216,"end_time":805.57,"speaker_id":1,"start_time":804.05,"speaker_name":null},{"text":"If you want to drop that into the homepage, that would be fine.","index":217,"end_time":810.41,"speaker_id":1,"start_time":806.69,"speaker_name":null},{"text":"If not, then, you know, we can put a placeholder in there.","index":218,"end_time":814.53,"speaker_id":1,"start_time":810.41,"speaker_name":null},{"text":"Is there an example of one right now that we could use?","index":219,"end_time":820.78,"speaker_id":1,"start_time":817.9,"speaker_name":null},{"text":"Let''s see.","index":220,"end_time":827.74,"speaker_id":1,"start_time":827.02,"speaker_name":null},{"text":"Have one on right now.","index":221,"end_time":834.78,"speaker_id":0,"start_time":832.859,"speaker_name":null},{"text":"We did, but the event passed.","index":222,"end_time":838.46,"speaker_id":0,"start_time":836.14,"speaker_name":null},{"text":"Okay, gotcha.","index":223,"end_time":840.06,"speaker_id":1,"start_time":838.94,"speaker_name":null},{"text":"All right, so maybe we keep it off for now.","index":224,"end_time":842.06,"speaker_id":1,"start_time":840.06,"speaker_name":null},{"text":"And that''s always something that we could add.","index":225,"end_time":845.59,"speaker_id":1,"start_time":843.99,"speaker_name":null},{"text":"All right, cool.","index":226,"end_time":846.83,"speaker_id":1,"start_time":845.99,"speaker_name":null},{"text":"So I think I''m good with the homepage.","index":227,"end_time":848.35,"speaker_id":1,"start_time":846.83,"speaker_name":null},{"text":"And then.","index":228,"end_time":848.79,"speaker_id":1,"start_time":848.35,"speaker_name":null},{"text":"Sounds like you got the integration piece still working.","index":229,"end_time":853.19,"speaker_id":1,"start_time":850.39,"speaker_name":null},{"text":"We will get this into our workflow.","index":230,"end_time":857.83,"speaker_id":1,"start_time":855.83,"speaker_name":null},{"text":"Should be able to have it pretty quickly, like Monday or Tuesday.","index":231,"end_time":862.63,"speaker_id":1,"start_time":858.55,"speaker_name":null},{"text":"See if I can get it in on Monday, but at the latest on Tuesday.","index":232,"end_time":867.03,"speaker_id":1,"start_time":863.75,"speaker_name":null},{"text":"Get this back over to you all.","index":233,"end_time":868.63,"speaker_id":1,"start_time":867.19,"speaker_name":null},{"text":"Okay.","index":234,"end_time":870.1,"speaker_id":0,"start_time":869.7,"speaker_name":null},{"text":"Oh, did you get my email about sending me just that image from the homepage?","index":235,"end_time":875.38,"speaker_id":0,"start_time":870.5,"speaker_name":null},{"text":"No, I see it now.","index":236,"end_time":881.3,"speaker_id":1,"start_time":879.94,"speaker_name":null},{"text":"The base files.","index":237,"end_time":884.42,"speaker_id":1,"start_time":883.14,"speaker_name":null},{"text":"Okay.","index":238,"end_time":893.62,"speaker_id":1,"start_time":892.98,"speaker_name":null},{"text":"How do you want to.","index":239,"end_time":899.53,"speaker_id":1,"start_time":898.77,"speaker_name":null},{"text":"How do you want to use the.","index":240,"end_time":900.61,"speaker_id":1,"start_time":899.53,"speaker_name":null},{"text":"It''s in Figma as the source.","index":241,"end_time":902.33,"speaker_id":1,"start_time":900.61,"speaker_name":null},{"text":"I can give you the FIGMA file, but how Would you like to.","index":242,"end_time":906.13,"speaker_id":1,"start_time":902.33,"speaker_name":null},{"text":"That''s fine.","index":243,"end_time":908.05,"speaker_id":0,"start_time":907.41,"speaker_name":null},{"text":"I just want to get the, like, actual image, and we just want to put a logo on it to put on the back of note cards that Leslie will use.","index":244,"end_time":915.25,"speaker_id":0,"start_time":908.05,"speaker_name":null},{"text":"I just like to.","index":245,"end_time":918.05,"speaker_id":0,"start_time":917.09,"speaker_name":null},{"text":"We need new note cards, and I would like them to be in the new branding.","index":246,"end_time":921.01,"speaker_id":0,"start_time":918.05,"speaker_name":null},{"text":"Yeah, seemed like the easiest way.","index":247,"end_time":924.27,"speaker_id":0,"start_time":921.71,"speaker_name":null},{"text":"All right, you.","index":248,"end_time":925.35,"speaker_id":1,"start_time":924.67,"speaker_name":null},{"text":"We want all the stats taken off and then just the image itself.","index":249,"end_time":928.83,"speaker_id":1,"start_time":925.35,"speaker_name":null},{"text":"Okay.","index":250,"end_time":930.19,"speaker_id":1,"start_time":929.71,"speaker_name":null},{"text":"Like, whatever is the least amount of work for you guys.","index":251,"end_time":933.03,"speaker_id":0,"start_time":930.19,"speaker_name":null},{"text":"I can figure it out.","index":252,"end_time":935.71,"speaker_id":0,"start_time":933.03,"speaker_name":null},{"text":"I''ll get this to you.","index":253,"end_time":936.99,"speaker_id":1,"start_time":935.87,"speaker_name":null},{"text":"I''ll just do this now.","index":254,"end_time":938.19,"speaker_id":1,"start_time":937.069,"speaker_name":null},{"text":"So.","index":255,"end_time":938.55,"speaker_id":1,"start_time":938.19,"speaker_name":null},{"text":"So we jump off.","index":256,"end_time":939.47,"speaker_id":1,"start_time":938.55,"speaker_name":null},{"text":"I''ll just hop in Figma and get these out to you.","index":257,"end_time":942.03,"speaker_id":1,"start_time":939.47,"speaker_name":null},{"text":"That would be spectacular.","index":258,"end_time":944.35,"speaker_id":0,"start_time":942.99,"speaker_name":null},{"text":"All right, I think we''re good.","index":259,"end_time":947.07,"speaker_id":1,"start_time":944.83,"speaker_name":null},{"text":"Other than that.","index":260,"end_time":947.97,"speaker_id":1,"start_time":947.41,"speaker_name":null},{"text":"Awesome.","index":261,"end_time":949.33,"speaker_id":0,"start_time":948.77,"speaker_name":null},{"text":"All right, thanks, Kylie.","index":262,"end_time":951.01,"speaker_id":1,"start_time":949.49,"speaker_name":null},{"text":"Be in touch.","index":263,"end_time":951.69,"speaker_id":1,"start_time":951.01,"speaker_name":null},{"text":"All right.","index":264,"end_time":952.13,"speaker_id":1,"start_time":951.69,"speaker_name":null},{"text":"Bye.","index":265,"end_time":952.61,"speaker_id":0,"start_time":952.13,"speaker_name":null},{"text":"Bye.","index":266,"end_time":953.09,"speaker_id":0,"start_time":952.61,"speaker_name":null}],"dateString":"2025-11-14T18:50:43.000Z","host_email":null,"meeting_link":null,"participants":[],"transcript_url":"https://app.fireflies.ai/view/01KA1V97N2Z434PCKE1SA3YTMW","organizer_email":"tristan.pelligrino@marketersindemand.com"}'::jsonb,
